function wordCount(words) {
  const map = {};

  for (const w of words) {
    if (!map[w]) {
      map[w] = 0;
    }

    map[w]++;
  }

  return map;
}

class Stack {
  constructor() {
    this.items = [];
  }

  push(x) {
    this.items.push(x);
  }

  pop() {
    return this.items.pop();
  }

  peek() {
    return this.items[this.items.length - 1];
  }

  isEmpty() {
    return this.items.length === 0;
  }
}

function factorial(n) {
  if (n === 0) return 1;
  return n * factorial(n - 1);
}

class Queue {
  constructor() {
    this.items = [];
  }

  enqueue(x) {
    this.items.push(x);
  }

  dequeue() {
    return this.items.shift();
  }

  peek() {
    return this.items[0];
  }

  isEmpty() {
    return this.items.length === 0;
  }
}

